 43→function waitForServer(port: number, timeoutMs = 10000): Promise<void> {
 44→  return new Promise((resolve, reject) => {
 45→    const start = Date.now();
 46→    const check = () => {
 47→      http
 48→        .get(`http://localhost:${port}/health`, (res) => {
 49→          if (res.statusCode === 200) {
 50→            resolve();
 51→          } else {
 52→            retry();
