 77→  return new Promise((resolve, reject) => {
 78→    http
 79→      .get(url, (res) => {
 80→        let body = "";
 81→        res.on("data", (chunk) => (body += chunk));
 82→        res.on("end", () =>
 83→          resolve({ status: res.statusCode || 0, body, headers: res.headers }),
 84→        );
 85→      })
 86→      .on("error", reject);
 87→  });
